module top_module (
    input clk,
    input reset,
    output reg [3:0] q
);
  wire _tap_clk = clk & {1{1'b1}};


    // 4-bit binary counter with reset logic
    always @(posedge clk) begin
        if (reset) begin
            q <= 0;
        end else begin
            q <= q + 1;
        end
    end

endmodule
